spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var size = 1;
    var color = '#EF4444';
    if (progress >= 0.25 && progress < 0.50) {
      size = 2;
      color = '#3B82F6';
    } else if (progress >= 0.50 && progress < 0.75) {
      size = 3;
      color = '#10B981';
    } else if (progress >= 0.75) {
      size = 4;
      color = '#F59E0B';
    }

    var midY = H / 2 - 25;
    var midX = W / 2;
    var cellSize = 22;

    // Draw grid of cells centered
    var startX = midX - (size * cellSize) / 2;
    var startY = midY - (size * cellSize) / 2;

    for (var r = 0; r < size; r++) {
      for (var c = 0; c < size; c++) {
        var cx = startX + c * cellSize;
        var cy = startY + r * cellSize;

        ctx.fillStyle = color;
        ctx.fillRect(cx, cy, cellSize - 2, cellSize - 2);
        ctx.strokeStyle = '#FFFFFF';
        ctx.lineWidth = 0.5;
        ctx.strokeRect(cx, cy, cellSize - 2, cellSize - 2);
      }
    }

    // Bottom text explanations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = 'bold 15px -apple-system, sans-serif';
    ctx.fillStyle = '#F3F4F6';

    if (size === 1) {
      ctx.fillText('1² = 1 × 1 = 1', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('1 unit block wide, 1 unit block high.', W / 2, H - 22);
    } else if (size === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('2² = 2 × 2 = 4', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('2 unit blocks wide, 2 unit blocks high. Total = 4 blocks.', W / 2, H - 22);
    } else if (size === 3) {
      ctx.fillStyle = '#34D399';
      ctx.fillText('3² = 3 × 3 = 9', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('3 unit blocks wide, 3 unit blocks high. Total = 9 blocks.', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#FBBF24';
      ctx.fillText('4² = 4 × 4 = 16', W / 2, H - 42);
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillStyle = '#9CA3AF';
      ctx.fillText('4 unit blocks wide, 4 unit blocks high. Total = 16 blocks.', W / 2, H - 22);
    }
  }
};
